/**
 * 동적 폼 렌더용 컬럼 디스크립터.
 */
export type TableColumnSchema = {
    /**
     * 컬럼명
     */
    name: string;
    /**
     * 논리 타입 (str/int/float/bool/uuid/datetime/json/enum)
     */
    type: string;
    /**
     * create 시 필수 여부
     */
    required: boolean;
    /**
     * update 시 수정 가능 여부
     */
    editable: boolean;
    /**
     * create 시 설정 가능 여부(자동생성 PK/타임스탬프는 False)
     */
    creatable: boolean;
    /**
     * 시크릿 여부(조회/감사에서 마스킹)
     */
    sensitive: boolean;
    /**
     * 문자열 최대 길이
     */
    max_length?: number | null;
    /**
     * enum 허용값 목록
     */
    enum?: Array<string> | null;
};

/**
 * 화이트리스트 테이블 1건의 목록 표현.
 */
export type TableInfo = {
    /**
     * 테이블 논리 키
     */
    key: string;
    /**
     * 사람이 읽는 라벨
     */
    label: string;
    /**
     * 허용 연산 목록 (read/create/update/delete)
     */
    ops: Array<string>;
    /**
     * 행 수(집계 실패 시 None)
     */
    row_count?: number | null;
};

/**
 * 단건 행 응답 엔벌로프(get/create/update). 값은 이미 마스킹 적용됨.
 */
export type TableRow = {
    /**
     * 테이블 논리 키
     */
    table: string;
    /**
     * 행 기본키(문자열)
     */
    pk: string;
    /**
     * 화이트리스트 컬럼 값(민감 컬럼 마스킹)
     */
    values: {
        [key: string]: unknown;
    };
};

/**
 * 행 생성/수정 요청. 화이트리스트 컬럼만 허용하며 그 외 키는 거부.
 */
export type TableRowWrite = {
    /**
     * 컬럼명→값 매핑(화이트리스트 컬럼만)
     */
    values: {
        [key: string]: unknown;
    };
};

/**
 * 행 페이지네이션 응답. 값은 화이트리스트 컬럼만 포함하며 민감 컬럼은 마스킹.
 */
export type TableRowsPage = {
    /**
     * 필터 적용 후 전체 행 수
     */
    total: number;
    /**
     * 페이지 크기
     */
    limit: number;
    /**
     * 오프셋
     */
    offset: number;
    /**
     * 행 목록(화이트리스트 컬럼만, 마스킹 적용)
     */
    rows: Array<{
        [key: string]: unknown;
    }>;
};

/**
 * 테이블 스키마(컬럼 디스크립터 집합) 응답.
 */
export type TableSchema = {
    /**
     * 테이블 논리 키
     */
    key: string;
    /**
     * 사람이 읽는 라벨
     */
    label: string;
    /**
     * 기본키 컬럼명
     */
    pk_column: string;
    /**
     * 허용 연산 목록
     */
    allowed_ops: Array<string>;
    /**
     * 컬럼 디스크립터 목록
     */
    columns: Array<TableColumnSchema>;
};

